verifiable.command_or_query:
source <(grep '^DIRECT_URL=' .env | sed 's/^/export /') && psql "$DIRECT_URL" -v ON_ERROR_STOP=1 <<'SQL'
BEGIN;
WITH pr AS (
  UPDATE "ProductRequirement" SET "deliveryStatus"='in_progress'
  WHERE id=(SELECT id FROM "ProductRequirement" LIMIT 1)
  RETURNING id, reference, "projectId"
), run AS (
  INSERT INTO "ForgeRun"(id,"projectId","ownerId",title,status,trigger,manifest)
  SELECT gen_random_uuid(), pr."projectId", (SELECT id FROM "Member" LIMIT 1), 't','queued','ad_hoc',
    jsonb_build_object('prds', jsonb_build_array(jsonb_build_object('reference', pr.reference)))
  FROM pr RETURNING id
)
UPDATE "ForgeRun" SET status='done' WHERE id=(SELECT id FROM run);
SELECT "deliveryStatus" FROM "ProductRequirement" WHERE "deliveryStatus"='review' LIMIT 1;
ROLLBACK;
SQL
